parameters.functionCode:
const error = $json.body?.data?.object?.last_payment_error || {};
const declineCode = (error.decline_code || '').toLowerCase();
const message = (error.message || '').toLowerCase();

let type = 'hard';

// FRAUD (highest priority)
if (
  ['fraudulent', 'restricted_card', 'stolen_card'].includes(declineCode) ||
  message.includes('fraud') ||
  message.includes('stolen') ||
  message.includes('restricted')
) {
  type = 'fraud';
}

// SOFT (retryable only)
else if (
  ['insufficient_funds', 'processing_error'].includes(declineCode) ||
  message.includes('insufficient') ||
  message.includes('temporary') ||
  message.includes('timeout')
) {
  type = 'soft';
}

// HARD (default – includes expired_card)
else {
  type = 'hard';
}

return [
  {
    json: {
      ...$json,
      failure_type: type,
      decline_code: declineCode || null
    }
  }
];
